import reflex as rx

class State(rx.State):
    prompt: str = ""

    @rx.event
    def set_prompt(self, value: str):
        self.prompt = value

def index():
    return rx.vstack(
        rx.heading("Hello Reflex"),
        rx.input(placeholder="Type here...", on_change=State.set_prompt),
        rx.text(State.prompt),
    )

app = rx.App()
app.add_page(index, title="Reflex App")
